function _previewText_(s, maxLen){
  maxLen = Math.max(20, Math.min(parseInt(maxLen || 90, 10) || 90, 200));
  let t = String(s || '').trim();
  if (!t) return '';
  // collapse whitespace/newlines
  t = t.replace(/\s+/g, ' ').trim();
  if (t.length <= maxLen) return t;
  return t.slice(0, maxLen - 1).trim() + '…';
}

function _json(obj){
  return ContentService
    .createTextOutput(JSON.stringify(obj))
    .setMimeType(ContentService.MimeType.JSON);
}

function _sanitizeText_(x){
  let s = String(x || '');
  s = s.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  s = s.trim();
  return s;
}

function _toInt(x, def){
  const n = parseInt(String(x||''), 10);
  return isNaN(n) ? def : n;
}

function _toBool(x){
  if (typeof x === 'boolean') return x;
  const s = String(x||'').trim().toLowerCase();
  if (s === 'true' || s === '1' || s === 'yes') return true;
  if (s === 'false' || s === '0' || s === 'no' || s === '') return false;
  return !!x;
}

function _iso(d){
  return new Date(d).toISOString();
}

function _isoCompact_(d){
  const s = new Date(d).toISOString();
  return s.replace(/[-:]/g,'').replace('.000Z','Z').replace('T','_');
}

function _id_(prefix){
  return String(prefix || 'ID') + '_' + Utilities.getUuid().replace(/-/g,'').slice(0,16).toUpperCase();
}

function _rand4_(){
  return Math.random().toString(16).slice(2,6).toUpperCase();
}

function _splitList_(s){
  return String(s||'')
    .split(/[,\s]+/)
    .map(x => String(x||'').trim())
    .filter(Boolean);
}

function _normArr_(v){
  if (Array.isArray(v)) return v.map(x => String(x||'').trim()).filter(Boolean);
  const s = String(v||'').trim();
  if (!s) return [];
  return s.split(',').map(x => String(x||'').trim()).filter(Boolean);
}

function _sha256Short_(s){
  const raw = Utilities.computeDigest(Utilities.DigestAlgorithm.SHA_256, String(s||''), Utilities.Charset.UTF_8);
  return raw.map(b => ('0' + (b & 0xFF).toString(16)).slice(-2)).join('').slice(0,24);
}

function _rlHit_(key, windowSec, maxHits){
  try{
    const cache = CacheService.getScriptCache();
    const k = 'rl:' + key;
    const cur = parseInt(cache.get(k) || '0', 10) || 0;
    if (cur >= maxHits) return { ok:false };
    cache.put(k, String(cur + 1), Math.max(5, windowSec));
    return { ok:true };
  } catch(e){
    return { ok:true }; // fail-open
  }
}
